### [개선 4] Cursor 기반 페이지네이션 적용

대량 팔로우(1000명 이상) 시 전체 조회는 여전히 느립니다.

```kotlin
// AFTER: Cursor 기반 페이지네이션
interface FollowRepository : JpaRepository<FollowEntity, String> {

    @Query("""
        SELECT new com.maum.backend.dto.follow.FollowProjection(
            f.followingId,
            u.nickname,
            u.profileImageUrl,
            f.createdAt
        )
        FROM FollowEntity f
        JOIN UserEntity u ON f.followingId = u.id
        WHERE f.followerId = :followerId
          AND (:cursor IS NULL OR f.createdAt < :cursor)
        ORDER BY f.createdAt DESC
    """)
    fun findFollowingWithCursor(
        @Param("followerId") followerId: String,
        @Param("cursor") cursor: LocalDateTime?,
        pageable: Pageable,
    ): List<FollowProjection>
}

// Service 호출
fun getFollowingList(
    userId: String,
    cursor: LocalDateTime?,
    size: Int = 20,
): FollowPageResponse {
    val cacheKey = if (cursor == null) "follow:following:$userId:first" else null

    if (cacheKey != null) {
        val cached = redisTemplate.opsForValue().get(cacheKey) as? FollowPageResponse
        if (cached != null) return cached
    }

    val items = followRepository.findFollowingWithCursor(
        followerId = userId,
        cursor = cursor,
        pageable = PageRequest.of(0, size + 1),
    )

    val hasNext = items.size > size
    val result = FollowPageResponse(
        items = items.take(size),
        nextCursor = if (hasNext) items[size - 1].createdAt else null,
        hasNext = hasNext,
    )

    if (cacheKey != null) {
        redisTemplate.opsForValue().set(cacheKey, result, Duration.ofSeconds(300))
    }

    return result
}
```

